mapper.insert:
MERGE INTO Bas_FirstAdd AS target USING ( VALUES
(#{item.customerId}, #{item.firstAddTime}, #{item.firstAdderDept}, #{item.firstAdderStore}, #{item.firstAdder})
) AS source (customer_id, first_add_time, first_adder_dept, first_adder_store, first_adder) ON target.customer_id = source.customer_id WHEN MATCHED THEN UPDATE SET first_add_time = source.first_add_time, first_adder_dept = source.first_adder_dept, first_adder_store = source.first_adder_store, first_adder = source.first_adder WHEN NOT MATCHED THEN INSERT (customer_id, first_add_time, first_adder_dept, first_adder_store, first_adder) VALUES (source.customer_id, source.first_add_time, source.first_adder_dept, source.first_adder_store, source.first_adder);
